   253→                  e.stopPropagation(); // Prevent card click
   254→                  handleDelete();
   255→                }}
   256→                className="block w-full text-left px-4 py-2 text-sm hover:bg-surface-light-elevated dark:hover:bg-neutral-800 text-status-error"
   257→              >
   258→                Delete
