   283→          const isDueSoon = daysUntilDue >= 0 && daysUntilDue <= 3;
   284→
   285→          return (
   286→            <span className={`text-xs px-2 py-0.5 rounded ${
   287→              isOverdue
   288→                ? 'bg-status-error-bg dark:bg-status-error-bg-dark text-status-error-text dark:text-status-error-text-dark'
   289→                : isDueSoon
   290→                ? 'bg-status-warning-bg dark:bg-status-warning-bg-dark text-status-warning-text dark:text-status-warning-text-dark'
   291→                : 'bg-neutral-100 dark:bg-neutral-800 text-accent-blue'
   292→            }`}>
   293→              📅 {dueDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
   294→            </span>
   295→          );
   296→        })()}
   297→
   298→        {/* Estimated Hours */}
   299→        {task.estimatedHours && (
   300→          <span className="text-xs px-2 py-0.5 rounded bg-neutral-100 dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary">
   301→            ⏱️ {task.estimatedHours}h
   302→          </span>
   303→        )}
   304→
   305→        {/* Time Tracked (Phase A: Time Tracking Integration) */}
   306→        {hasTimeTracked && (
   307→          <span
   308→            onClick={(e) => {
   309→              e.stopPropagation();
   310→              if (onCardClick) {
   311→                onCardClick(task);
   312→              }
   313→            }}
   314→            className={`text-xs px-2 py-0.5 rounded font-medium cursor-pointer transition-all hover:scale-105 ${
   315→              isTimerActive
   316→                ? 'bg-accent-blue text-white hover:bg-accent-blue/90 animate-pulse'
   317→                : 'bg-neutral-100 dark:bg-neutral-800 text-accent-blue dark:text-accent-blue-hover'
   318→            }`}
   319→            title={isTimerActive ? 'Timer running - click to view' : 'Total time tracked - click to view'}
   320→          >
   321→            {isTimerActive && '⏱️ '}🕐 {formatTime(totalSeconds)}
   322→          </span>
   323→        )}
   324→
   325→        {/* Tags */}
   326→        {task.tags && task.tags.length > 0 && task.tags.map((tag) => (
   327→          <span
   328→            key={tag}
   329→            className="text-xs px-2 py-0.5 rounded bg-accent-blue/10 dark:bg-accent-blue/20 text-accent-blue dark:text-accent-blue-hover"
   330→          >
   331→            #{tag}
   332→          </span>
   333→        ))}
   334→
   335→        {/* Dependency Indicators (PHASE 5 PART 6) */}
   336→        {(() => {
   337→          const blockers = getBlockers(task.id);
   338→          const incompleteBlockers = blockers.filter((b) => b.status !== 'done');
   339→
   340→          if (incompleteBlockers.length > 0) {
   341→            return (
   342→              <span
   343→                onClick={(e) => {
   344→                  e.stopPropagation();
   345→                  if (onCardClick) {
   346→                    onCardClick(task);
   347→                  }
   348→                }}
   349→                className="text-xs px-2 py-0.5 rounded font-medium cursor-pointer transition-all hover:scale-105 bg-status-warning-bg dark:bg-status-warning-bg-dark text-status-warning-text dark:text-status-warning-text-dark hover:opacity-80"
   350→                title={`Blocked by ${incompleteBlockers.length} task(s)`}
   351→              >
   352→                🔒 Blocked by {incompleteBlockers.length}
   353→              </span>
   354→            );
   355→          }
   356→
   357→          const blocked = getBlocked(task.id);
   358→          if (blocked.length > 0) {
   359→            return (
   360→              <span
   361→                onClick={(e) => {
   362→                  e.stopPropagation();
   363→                  if (onCardClick) {
   364→                    onCardClick(task);
