   366→                }}
   367→                className="text-xs px-2 py-0.5 rounded font-medium cursor-pointer transition-all hover:scale-105 bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-300 dark:hover:bg-neutral-600"
   368→                title={`Blocking ${blocked.length} task(s)`}
   369→              >
   370→                ⚠️ Blocks {blocked.length}
   371→              </span>
   372→            );
   373→          }
   374→
   375→          return null;
   376→        })()}
   377→
   378→        {/* Subtask Progress Badge */}
   379→        {task.subtasks && task.subtasks.length > 0 && (() => {
   380→          const completedCount = task.subtasks.filter(st => st.completed).length;
   381→          const totalCount = task.subtasks.length;
   382→          const isComplete = completedCount === totalCount;
   383→
   384→          return (
   385→            <span
   386→              onClick={(e) => {
   387→                e.stopPropagation();
   388→                if (onCardClick) {
