   394→                  ? 'bg-status-success text-white hover:bg-status-success/90'
   395→                  : completedCount > 0
   396→                  ? 'bg-accent-blue text-white hover:bg-accent-blue/90'
   397→                  : 'bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-300 dark:hover:bg-neutral-600'
