  1106→                return hours < 0.1 ? '<0.1h' : `${hours.toFixed(1)}h`;
  1107→              };
  1108→
  1109→              return (
  1110→                <div className="space-y-4">
  1111→                  {/* Timer Controls */}
  1112→                  <div className="bg-surface-light-elevated dark:bg-surface-dark rounded-lg p-4">
  1113→                    <div className="flex items-center justify-between mb-3">
  1114→                      <div>
  1115→                        <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
  1116→                          Total Time: {formatTime(totalSeconds)}
  1117→                        </h3>
