import React, { useState, useEffect, useCallback } from 'react';
import { Modal } from '../../components/Modal';
import { useKanbanStore } from '../../stores/useKanbanStore';
import { useTimeTrackingStore } from '../../stores/useTimeTrackingStore';
import type { Task, TaskPriority, TaskStatus, EffortEstimate, CustomStatus } from '../../types';

interface CardDetailPanelProps {
  task: Task | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (taskId: string, updates: Partial<Task>) => void;
  columns: Array<{ id: string; title: string; color: string }>;
  initialTab?: 'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking';
  onCardClick?: (task: Task) => void;
}

/**
 * Card Detail Panel
 * Full-screen modal for viewing and editing task details
 *
 * Features:
 * - Left side: Task metadata (title, description, dates, priority, tags, status)
 * - Right side: Tabs (Checklist, Comments, Activity Log)
 * - Inline editing (auto-save on blur)
 * - Keyboard shortcuts (Esc to close, Cmd+Enter to save)
 * - Tab persistence (remembers last active tab)
 * - Responsive design (mobile, tablet, desktop)
 */
export const CardDetailPanel: React.FC<CardDetailPanelProps> = ({
  task,
  isOpen,
  onClose,
  onSave,
  columns,
  initialTab,
  onCardClick,
}) => {
  // Kanban store actions
  const {
    tasks,
    addChecklistItem,
    updateChecklistItem,
    deleteChecklistItem,
    toggleChecklistItem,
    addComment,
    addSubtask,
    deleteSubtask,
    toggleSubtask,
    addDependency,
    removeDependency,
    dependencies,
    updateEffort,
    updateCustomStatus,
    startTimer,
    stopTimer: stopKanbanTimer,
    updateTimeEstimate,
  } = useKanbanStore();

  // Time tracking store (Phase A: Time Tracking Integration)
  const {
    getEntriesForCard,
    getTotalTimeForCard,
    startTimerForCard,
    stopTimer,
    activeEntry,
  } = useTimeTrackingStore();

  // Tab state with persistence
  const [activeTab, setActiveTab] = useState<'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking'>(() => {
    if (initialTab) return initialTab;
    const saved = localStorage.getItem('kanban-detail-panel-tab');
    return (saved as 'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking') || 'subtasks';
  });

  // Sync activeTab with initialTab when it changes
  useEffect(() => {
    if (initialTab) {
      setActiveTab(initialTab);
    }
  }, [initialTab]);

  // Local state for editing (synced with task prop)
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [startDate, setStartDate] = useState<string | null>(null);
  const [dueDate, setDueDate] = useState<string | null>(null);
  const [priority, setPriority] = useState<TaskPriority>('medium');
  const [tags, setTags] = useState<string[]>([]);
  const [status, setStatus] = useState<TaskStatus>('todo');
  const [newTag, setNewTag] = useState('');
  const [effort, setEffort] = useState<EffortEstimate | undefined>(undefined);
  const [customStatus, setCustomStatus] = useState<CustomStatus | undefined>(undefined);
  const [timeEstimate, setTimeEstimate] = useState<number | undefined>(undefined);

  // Checklist state
  const [newChecklistItem, setNewChecklistItem] = useState('');

  // Comment state
  const [newCommentText, setNewCommentText] = useState('');

  // Subtask state
  const [showAddSubtaskForm, setShowAddSubtaskForm] = useState(false);
  const [newSubtaskTitle, setNewSubtaskTitle] = useState('');
  const [newSubtaskDescription, setNewSubtaskDescription] = useState('');
  const [newSubtaskPriority, setNewSubtaskPriority] = useState<TaskPriority>('medium');
  const [newSubtaskDueDate, setNewSubtaskDueDate] = useState('');

  // Dependency state
  const [selectedBlocker, setSelectedBlocker] = useState('');
  const [selectedBlocked, setSelectedBlocked] = useState('');

  // Sync local state with task prop when task changes
  useEffect(() => {
    if (task) {
      setTitle(task.title);
      setDescription(task.description);
      setStartDate(task.startDate);
      setDueDate(task.dueDate);
      setPriority(task.priority);
      setTags(task.tags);
      setStatus(task.status);
      setEffort(task.effort);
      setCustomStatus(task.customStatus);
      setTimeEstimate(task.timeTracking?.estimated);
    }
  }, [task]);

  // Tab persistence
  useEffect(() => {
    localStorage.setItem('kanban-detail-panel-tab', activeTab);
  }, [activeTab]);

  // Save and close handler
  const handleSaveAndClose = useCallback(() => {
    if (!task) return;
    onSave(task.id, {
      title,
      description,
      startDate,
      dueDate,
      priority,
      tags,
      status,
    });
    onClose();
  }, [task, onSave, onClose, title, description, startDate, dueDate, priority, tags, status]);

  // Keyboard shortcut: Cmd+Enter to save and close
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'Enter' && isOpen) {
        e.preventDefault();
        handleSaveAndClose();
      }
    };

    if (isOpen) {
      document.addEventListener('keydown', handleKeyDown);
    }

    return () => {
      document.removeEventListener('keydown', handleKeyDown);
    };
  }, [isOpen, handleSaveAndClose]);

  if (!task) return null;

  const handleFieldBlur = (field: keyof Task, value: unknown) => {
    // Auto-save on blur
    onSave(task.id, { [field]: value });
  };

  const handleAddTag = () => {
    if (newTag.trim() && !tags.includes(newTag.trim())) {
      const updatedTags = [...tags, newTag.trim()];
      setTags(updatedTags);
      onSave(task.id, { tags: updatedTags });
      setNewTag('');
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    const updatedTags = tags.filter(tag => tag !== tagToRemove);
    setTags(updatedTags);
    onSave(task.id, { tags: updatedTags });
  };

  // Dependency handlers
  const getBlockers = () => {
    if (!task || !dependencies) return [];
    return dependencies
      .filter(dep => dep.targetTaskId === task.id)
      .map(dep => tasks.find(t => t.id === dep.sourceTaskId))
      .filter(Boolean) as typeof tasks;
  };

  const getBlocked = () => {
    if (!task || !dependencies) return [];
    return dependencies
      .filter(dep => dep.sourceTaskId === task.id)
      .map(dep => tasks.find(t => t.id === dep.targetTaskId))
      .filter(Boolean) as typeof tasks;
  };

  const handleAddBlocker = () => {
    if (!task || !selectedBlocker) return;
    addDependency(selectedBlocker, task.id);
    setSelectedBlocker('');
  };

  const handleAddBlocked = () => {
    if (!task || !selectedBlocked) return;
    addDependency(task.id, selectedBlocked);
    setSelectedBlocked('');
  };

  const handleRemoveDependency = (dependencyId: string) => {
    removeDependency(dependencyId);
  };

  const availableTasks = tasks.filter(t => t.id !== task?.id);

  const priorityColors = {
    low: 'bg-status-info text-white',
    medium: 'bg-status-warning text-white',
    high: 'bg-status-error text-white',
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={task.title} maxWidth="2xl">
      <div className="flex flex-col md:flex-row gap-6">
        {/* Left Side: Task Metadata (60%) */}
        <div className="w-full md:w-3/5 space-y-6">
          {/* Title */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Title
            </label>
            <input
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              onBlur={() => handleFieldBlur('title', title)}
              className="w-full text-2xl font-semibold bg-transparent border-none outline-none text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue rounded px-2 py-1"
              autoFocus
            />
          </div>

          {/* Description */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Description
            </label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              onBlur={() => handleFieldBlur('description', description)}
              placeholder="Add a description..."
              className="w-full min-h-[120px] p-3 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue outline-none resize-y"
              rows={6}
            />
          </div>

          {/* Dates */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
                Start Date
              </label>
              <input
                type="date"
                value={startDate || ''}
                onChange={(e) => {
                  setStartDate(e.target.value || null);
                  handleFieldBlur('startDate', e.target.value || null);
                }}
                className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
              />
            </div>
            <div>
              <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
                Due Date
              </label>
              <input
                type="date"
                value={dueDate || ''}
                onChange={(e) => {
                  setDueDate(e.target.value || null);
                  handleFieldBlur('dueDate', e.target.value || null);
                }}
                className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
              />
            </div>
          </div>

          {/* Priority */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Priority
            </label>
            <select
              value={priority}
              onChange={(e) => {
                const newPriority = e.target.value as TaskPriority;
                setPriority(newPriority);
                handleFieldBlur('priority', newPriority);
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              <option value="low">Low</option>
              <option value="medium">Medium</option>
              <option value="high">High</option>
            </select>
            <div className="mt-2">
              <span className={`inline-block px-3 py-1 text-xs font-medium rounded-full ${priorityColors[priority]}`}>
                {priority.charAt(0).toUpperCase() + priority.slice(1)} Priority
              </span>
            </div>
          </div>

          {/* Effort (Story Points) - Phase B */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Effort (Story Points)
            </label>
            <select
              value={effort || ''}
              onChange={(e) => {
                const newEffort = e.target.value ? (parseInt(e.target.value) as EffortEstimate) : undefined;
                setEffort(newEffort);
                if (task) {
                  updateEffort(task.id, newEffort);
                }
